Scanner input = new Scanner(System.in);
int sum = 0;

while (true) {
    System.out.print("Enter a number (-1 to stop): ");
    int n = input.nextInt();
    if (n == -1) {
        break;                 // leave the loop right now
    }
    sum += n;                  // only runs for real numbers
}
System.out.println("Sum: " + sum);

