boolean nameFilled = false;
boolean adult = true;

// "not valid" — two equivalent ways:
boolean invalidA = !(nameFilled && adult);
boolean invalidB = !nameFilled || !adult;   // De Morgan's

System.out.println(invalidA);   // true
System.out.println(invalidB);   // true — same result

